/**
 * Settings Override Resolver — PreToolUse hook (M168 Phase 4, #1914)
 *
 * On every PreToolUse, read the per-session settings_overrides rows from
 * the SQLite registry and snapshot them to a state file at
 * `~/.claude/state/orchestkit/<sid>/active-overrides.json`. Downstream
 * tooling, status lines, and the user can inspect the file to see which
 * /effort, /model, etc. overrides are active for this session.
 *
 * This hook reads only — it never writes to the DB or to settings.json,
 * and never blocks tool execution. If the DB doesn't exist yet (fresh
 * session before Layer 1 finished registering), the hook silently no-ops.
 *
 * Hook event: PreToolUse (async, timeout: 3s).
 */

import type { HookContext, HookInput, HookResult } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { listOverrides } from '../lib/settings-override.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { getHomeDir } from '../lib/paths.js';
import { safeIdentifier } from '../lib/safe-fs.js';
import { join } from 'node:path';

const HOOK_NAME = 'pretool/settings-override-resolver';

/** Where the snapshot lives — under ~/.claude/state/orchestkit/<sid>/. */
function snapshotPath(sid: string): string {
  const safeSid = safeIdentifier(sid, 'unknown');
  return join(
    getHomeDir(),
    '.claude',
    'state',
    'orchestkit',
    safeSid,
    'active-overrides.json',
  );
}

export function settingsOverrideResolver(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const sid = input.session_id;
  if (!sid) return outputSilentSuccess();

  let entries: { key: string; value: string }[] = [];
  try {
    entries = listOverrides(sid);
  } catch (err) {
    // DB may not exist yet — first PreToolUse can race with session-registrar.
    ctx.log(HOOK_NAME, `listOverrides failed: ${(err as Error).message}`);
    return outputSilentSuccess();
  }

  // Always write the snapshot (even if empty) so a stale file from a
  // previous override doesn't mislead callers into thinking it's still set.
  const payload = JSON.stringify({
    sid,
    updated_at: Math.floor(Date.now() / 1000),
    overrides: entries,
  });
  try {
    atomicWriteSync(snapshotPath(sid), payload);
  } catch (err) {
    ctx.log(HOOK_NAME, `snapshot write failed: ${(err as Error).message}`);
  }

  return outputSilentSuccess();
}

/** Exposed for tests. */
export const __internals = { snapshotPath };
